const CpsHl = ({ text, style = {} }) => {
  if (!text) return null;
  const parts = String(text).split(/(\[.*?\])/g);
  return <span style={style}>{parts.map((p, i) => p.startsWith("[") && p.endsWith("]")
    ? <span key={i} style={{ background: CPS_YELLOW, borderRadius: 2, padding: "0 2px" }}>{p}</span>
    : <span key={i}>{p}</span>)}</span>;
};

const CpsCell = ({ value, onChange, style = {}, align = "left", placeholder = "" }) => {
  const [editing, setEditing] = useState(false);
  const [temp, setTemp] = useState(value);
  const inputRef = useRef(null);
  useEffect(() => { setTemp(value); }, [value]);
  const commit = () => { setEditing(false); onChange(temp); };
  const isPlaceholder = (v) => (v && v.startsWith("[") && v.endsWith("]")) || false;
  const startEdit = () => {
    setTemp(isPlaceholder(value) ? "" : value);
    setEditing(true);
  };
  useEffect(() => { if (editing && inputRef.current) inputRef.current.select(); }, [editing]);
  if (editing) {
    return <input ref={inputRef} autoFocus value={temp} onChange={e => setTemp(e.target.value)}
      onBlur={commit} onKeyDown={e => e.key === "Enter" && commit()}
      placeholder={placeholder || (isPlaceholder(value) ? value.slice(1, -1) : "")}
      style={{ fontFamily: CPS_F, fontSize: 9, letterSpacing: CPS_LS, border: "none", outline: "none",
        background: "#FFFDE7", width: "100%", boxSizing: "border-box", padding: "3px 6px",
        textAlign: align, ...style }} />;
  }
  return (
    <div onClick={startEdit}
      style={{ fontFamily: CPS_F, fontSize: 9, letterSpacing: CPS_LS, cursor: "text", padding: "3px 6px",
        minHeight: 18, textAlign: align, whiteSpace: "pre-wrap", ...style }}
      onMouseEnter={e => e.currentTarget.style.background = "#fafafa"}
      onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
      {value ? <CpsHl text={value} /> : <span style={{ color: "#ddd" }}>{placeholder || "—"}</span>}
    </div>
  );
};

const CpsOnnaLogo = () => {
  const [loaded, setLoaded] = useState(false);
  const fontB64 = ""; // ~44KB base64 font
  if (!loaded) { try { const s=document.createElement("style"); s.textContent=`@font-face{font-family:'SackersGothic';src:url('data:application/x-font-opentype;base64,${fontB64}')format('opentype')}`; document.head.appendChild(s); setLoaded(true); } catch(e){} }
  return <span style={{ fontFamily:"'SackersGothic','Didot',serif",fontSize:30,fontWeight:400,letterSpacing:1,color:"#000" }}>onna</span>;
};

/* ======= STATUS ======= */
const CPS_STATUSES = ["Not Started", "In Progress", "In Review", "Approved", "Complete", "Blocked"];
const CPS_STATUS_COLORS = {
  "Not Started": { bg: "#f4f4f4", text: "#999" },
  "In Progress": { bg: "#FFF3E0", text: "#E65100" },
  "In Review": { bg: "#E3F2FD", text: "#1565C0" },
  "Approved": { bg: "#E8F5E9", text: "#2E7D32" },
  "Complete": { bg: "#000", text: "#fff" },
  "Blocked": { bg: "#FCE4EC", text: "#C62828" },
};

const CpsStatusBadge = ({ value, onChange }) => {
  const cycle = () => {
    const i = CPS_STATUSES.indexOf(value);
    onChange(CPS_STATUSES[(i + 1) % STATUSES.length]);
  };
  const c = CPS_STATUS_COLORS[value] || CPS_STATUS_COLORS["Not Started"];
  return (
    <div onClick={cycle} style={{
      fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS,
      background: c.bg, color: c.text, padding: "3px 6px", borderRadius: 2,
      cursor: "pointer", textAlign: "center", userSelect: "none", whiteSpace: "nowrap",
      textTransform: "uppercase",
    }}>{value}</div>
  );
};

