            const targetPage=pgIdx!=null?pgIdx:wnIdx!=null?wnIdx:ordIdx!=null?ordIdx:revOrdIdx!=null?revOrdIdx:bareIdx!=null&&bareIdx>=0&&bareIdx<cfg.originalDoc.pages.length?bareIdx:null;
